function solve(m, n, waitCost) {
    const base = new Array(m);
    for (let i = 0; i < m; i++) {
        base[i] = new Array(n);
        for (let j = 0; j < n; j++) {
            if (i === m-1 && j === n-1) {
                base[i][j] = (i+1) * (j+1);
            } else {
                base[i][j] = (i+1) * (j+1) + waitCost[i][j];
            }
        }
    }

    const dp = new Array(m);
    for (let i = 0; i < m; i++) {
        dp[i] = new Array(n).fill(Number.MAX_SAFE_INTEGER);
    }
    dp[0][0] = 0;

    for (let i = 0; i < m; i++) {
        for (let j = 0; j < n; j++) {
            if (i > 0) {
                dp[i][j] = Math.min(dp[i][j], dp[i-1][j] + base[i][j]);
            }
            if (j > 0) {
                dp[i][j] = Math.min(dp[i][j], dp[i][j-1] + base[i][j]);
            }
        }
    }

    return 1 + dp[m-1][n-1];
}
